1	import type { Page, Request } from '@playwright/test';
2	import { expect, test as baseTest } from '@playwright/test';
3	
4	export { expect };
5	export type { Page };
6	
7	const parseHost = (url: string): string | null => {
8	    try {
9	        return new URL(url).host;
10	    } catch {
11	        return null;
12	    }
13	};
14	
15	/**
16	 * Extended Playwright test fixture. Wraps every test's `page` with listeners
17	 * that log JS runtime errors and failed same-origin requests to the console,
18	 * making asset-loading or hydration failures visible in test output. The
19	 * request filter is derived from the configured `baseURL` (host + port), so
20	 * cross-origin noise (e.g. Google Maps) is suppressed regardless of which host
21	 * the tests run against.
22	 *
23	 * Import `test` and `expect` from here instead of `@playwright/test`.
24	 */
25	export const test = baseTest.extend({
26	    page: async ({ page, baseURL }, use) => {
27	        const allowedHost = baseURL ? parseHost(baseURL) : null;
28	        const onPageError = (err: Error) => console.error('Page JS error:', err);
29	        const onRequestFailed = (req: Request) => {
30	            const errorText = req.failure()?.errorText ?? '';
31	            // Navigation-initiated cancellations are expected (e.g. SSE connections
32	            // dropped on page change) and vary by browser:
33	            // Chromium: net::ERR_ABORTED, Firefox: NS_BINDING_ABORTED, WebKit: Load request cancelled
34	            if (/cancel|ABORTED/i.test(errorText)) return;
35	            const reqHost = parseHost(req.url());
36	            if (!allowedHost || !reqHost || reqHost === allowedHost) {
37	                console.error('Request failed:', req.url(), errorText);
38	            }
39	        };
40	        page.on('pageerror', onPageError);
41	        page.on('requestfailed', onRequestFailed);
42	        try {
43	            await use(page);
44	        } finally {
45	            page.off('pageerror', onPageError);
46	            page.off('requestfailed', onRequestFailed);
47	        }
48	    },
49	});
