1	import 'server-only';
2	
3	import { sendGameInvitations } from '@/lib/gameInvitations';
4	import { getInvitationDecision } from '@/lib/invitations';
5	import type { NewGameInput } from '@/types/actions/TriggerInvitations';
6	
7	interface TriggerInvitationsDeps {
8	    getInvitationDecision: typeof getInvitationDecision;
9	    sendGameInvitations: typeof sendGameInvitations;
10	}
11	
12	const defaultDeps: TriggerInvitationsDeps = {
13	    getInvitationDecision,
14	    sendGameInvitations,
15	};
16	
17	/**
18	 * Triggers the process of sending game invitations based on the provided input
19	 * and dependencies.
20	 *
21	 * @param data - The input data for the new game, including optional custom
22	 * message and override time check.
23	 * @param deps - The dependencies required for triggering invitations, such as
24	 * decision logic and sending functionality. Defaults to `defaultDeps`.
25	 * @returns A promise that resolves to the invitation decision, indicating the
26	 * status and associated game day ID if applicable.
27	 */
28	export async function triggerInvitationsCore(
29	    data: NewGameInput,
30	    deps: TriggerInvitationsDeps = defaultDeps,
31	) {
32	    const customMessage = data.customMessage?.trim();
33	    const decision = await deps.getInvitationDecision(data.overrideTimeCheck);
34	
35	    if (decision.status === 'ready' && decision.gameDayId) {
36	        await deps.sendGameInvitations(decision.gameDayId, customMessage);
37	    }
38	
39	    return decision;
40	}
