6	import { sendEmail } from '@/actions/sendEmail';
7	import { normalizeEmail } from '@/lib/email/normalizeEmail';
8	import { NotFoundError } from '@/lib/errors';
9	import { getPublicBaseUrl } from '@/lib/urls';
10	import gameDayService from '@/services/GameDay';
11	import gameInvitationService from '@/services/GameInvitation';
12	import outcomeService from '@/services/Outcome';
13	import playerService from '@/services/Player';
14	import { GameInvitationResponseDetails } from '@/types/GameInvitationResponseDetails';
15	
16	const buildInvitationToken = () => crypto.randomUUID();
17	
18	/**
19	 * Builds an HTML email invitation for a game.
20	 *
21	 * @param params - The invitation parameters
22	 * @param params.playerName - The name of the player being invited
23	 * @param params.inviteLink - The URL link for the player to respond to the
24	 * invitation
25	 * @param params.gameDate - The date of the game
26	 * @param params.customMessage - Optional custom message to include in the email
27	 * @returns An HTML string containing the formatted email invitation
28	 *
29	 * @remarks
30	 * The function escapes all HTML content to prevent injection attacks. The
31	 * returned HTML includes inline styles for better email client compatibility.
32	 */
33	export const buildInvitationEmail = ({
34	    playerName,
35	    inviteLink,
36	    gameDate,
37	    customMessage,
38	}: {
39	    playerName: string;
40	    inviteLink: string;
41	    gameDate: Date;
42	    customMessage?: string | null;
43	}) => {
44	    const safeName = escapeHtml(playerName);
45	    const safeMessage = customMessage ? escapeHtml(customMessage) : '';
46	    const safeLink = escapeHtml(inviteLink);
47	    const safeDate = escapeHtml(gameDate.toDateString());
48	
49	    return [
50	        '<div style="font-family:Arial,Helvetica,sans-serif;line-height:1.5;">',
51	        `<p>Hello ${safeName},</p>`,
52	        `<p>The next Toastboy FC game is on ${safeDate}.</p>`,
53	        safeMessage ? `<p>${safeMessage}</p>` : '',
54	        `<p>Please respond here: <a href="${safeLink}">submit your response</a></p>`,
55	        '<p>You can change it later if you need to, even if the teams have been picked - either by clicking ',
56	        'on the link in the email you received, or by logging in to the site at the game page.</p>',
57	        '<p>Cheers,<br />Jon</p>',
58	        '</div>',
59	    ].filter(Boolean).join('');
60	};
61	
62	/**
63	 * Sends game invitations to all active players for a specific game day.
64	 *
65	 * This function retrieves the game day details, filters active players, clears existing invitations,
66	 * and sends email invitations to each player with a unique token. Each player receives an invitation
67	 * at all their registered email addresses (account email and extra emails).
68	 *
69	 * @param params - The parameters for sending invitations
70	 * @param params.gameDayId - The ID of the game day for which invitations are being sent
71	 * @param params.customMessage - Optional custom message to include in the invitation email
72	 *
73	 * @throws {Error} If the game day with the specified ID is not found
74	 *
75	 * @returns A promise that resolves when all invitations have been sent and the game day is marked as mail sent
76	 *
77	 * @remarks
78	 * - This function deletes all existing game invitations before creating new ones
79	 * - Players with no valid email addresses are skipped
80	 * - Duplicate email addresses for the same player are automatically removed
81	 * - All emails are normalized before sending
82	 * - A unique invitation token is generated for each player to track responses
83	 */
84	export async function sendGameInvitations(
85	    gameDayId: number,
86	    customMessage?: string,
87	) {
88	    const gameDay = await gameDayService.get(gameDayId);
89	    if (!gameDay) {
90	        throw new NotFoundError('Game day not found.', {
91	            details: { gameDayId },
92	            publicMessage: 'Game day not found.',
93	        });
94	    }
95	
96	    const players = await playerService.getAll();
97	    const activePlayers = players.filter((player) => !player.finished);
98	
99	    await gameInvitationService.deleteAll();
100	
101	    const baseUrl = getPublicBaseUrl();
102	    const sendAt = new Date();
103	
104	    const invitations: { uuid: string; playerId: number; gameDayId: number }[] = [];
105	    const emailTasks = activePlayers.map(async (player) => {
106	        const emails = [
107	            player.accountEmail,
108	            ...player.extraEmails.map((extraEmail) => extraEmail.email),
109	        ]
110	            .map(normalizeEmail)
111	            .filter((email) => email.length > 0);
112	
113	        const uniqueEmails = Array.from(new Set(emails));
114	        if (uniqueEmails.length === 0) {
115	            return null;
116	        }
117	
118	        const token = buildInvitationToken();
119	        invitations.push({
120	            uuid: token,
121	            playerId: player.id,
122	            gameDayId,
123	        });
124	
125	        const inviteLink = `${baseUrl}/api/footy/response/${encodeURIComponent(token)}`;
126	        const html = buildInvitationEmail({
127	            playerName: player.name,
128	            inviteLink,
129	            gameDate: gameDay.date,
130	            customMessage,
131	        });
132	
133	        await sendEmail({
134	            to: uniqueEmails.join(','),
135	            subject: 'Toastboy FC invitation',
136	            html,
137	        });
138	        return token;
139	    });
140	
141	    if (invitations.length > 0) {
142	        await gameInvitationService.createMany(invitations);
143	    }
144	    await Promise.all(emailTasks);
145	    await gameDayService.markMailSent(gameDayId, sendAt);
146	}
147	
148	export async function getGameInvitationResponseDetails(token: string): Promise<GameInvitationResponseDetails | null> {
149	    if (!token) return null;
150	
151	    const invitation = await gameInvitationService.get(token);
152	    if (!invitation) return null;
153	
154	    const player = await playerService.getById(invitation.playerId);
155	    if (!player) return null;
156	
157	    const playerLogin = await playerService.getLogin(player.id.toString());
158	    const outcome = await outcomeService.get(invitation.gameDayId, invitation.playerId);
159	
160	    return {
161	        token,
162	        playerId: player.id,
163	        playerName: player.name,
164	        playerLogin,
165	        gameDayId: invitation.gameDayId,
166	        response: outcome?.response ?? null,
167	        goalie: outcome?.goalie ?? player.goalie ?? false,
168	        comment: outcome?.comment ?? null,
169	    };
170	}
