19	export async function waitForMessage(
20	    request: APIRequestContext,
21	    subject: string,
22	    { attempts = 30, intervalMs = 1000 }: { attempts?: number; intervalMs?: number } = {},
23	): Promise<MailpitMessage | undefined> {
24	    for (let i = 0; i < attempts; i++) {
25	        const res = await request.get(`${MAILPIT_URL}/api/v1/messages?limit=50`);
26	        const data = await res.json() as { messages?: MailpitMessage[] };
27	        const match = data.messages?.find((m) => m.Subject === subject);
28	        if (match) return match;
29	        await new Promise((resolve) => setTimeout(resolve, intervalMs));
30	    }
31	    return undefined;
32	}
