331	     *   unplayed sentinel entries (gameDayId: 0, points: null) so the result
332	     *   is always formHistory entries long.
333	     *
334	     * Sorting behavior:
335	     * - Players are ordered with goalies first.
336	     * - Within each group, players are ordered alphabetically by name.
337	     * @returns A promise resolving to the enriched player records.
338	     * @throws If there is an error fetching the data.
339	     */
340	    async getTeamPlayersByGameDay(
341	        gameDayId: number,
342	        team: TeamName,
343	        formHistory = 5,
344	    ): Promise<TeamPlayerType[]> {
345	        const validatedGameDayId = z.number().int().min(1).parse(gameDayId);
346	        const validatedTeam = TeamNameSchema.parse(team);
347	        const validatedHistory = z.number().int().min(0).parse(formHistory);
348	
349	        const outcomes = await prisma.outcome.findMany({
350	            where: {
351	                gameDayId: validatedGameDayId,
352	                team: validatedTeam,
353	            },
354	            include: {
355	                player: {
356	                    include: {
357	                        outcomes: {
358	                            where: {
359	                                gameDayId: { lt: validatedGameDayId },
360	                                points: { not: null },
361	                            },
362	                            orderBy: { gameDayId: 'desc' },
363	                            take: validatedHistory,
364	                            include: { gameDay: true },
365	                        },
366	                    },
367	                },
368	            },
369	            orderBy: [
370	                { goalie: 'desc' },
371	                { player: { name: 'asc' } },
372	            ],
373	        });
374	
375	        return outcomes.map(({ player, ...outcome }) => {
376	            if (!player) {
377	                throw new InternalError(`Outcome ${outcome.id} is missing its player relation.`, {
378	                    details: {
379	                        outcomeId: outcome.id,
380	                        gameDayId: outcome.gameDayId,
381	                        playerId: outcome.playerId,
382	                        team: outcome.team,
383	                    },
384	                });
385	            }
386	            const { outcomes: playerOutcomes = [], ...playerData } = player;
387	
388	            // Outcomes arrive newest-first; reverse so the arc reads oldest→newest.
389	            const actualForm = [...playerOutcomes].reverse();
390	
391	            // Left-pad with unplayed sentinels for players newer than formHistory games.
392	            const paddingCount = Math.max(0, validatedHistory - actualForm.length);
393	            const padding = Array.from({ length: paddingCount }, () => ({
394	                id: 0,
395	                gameDayId: 0,
396	                playerId: playerData.id,
397	                response: null,
398	                responseInterval: null,
399	                points: null,
400	                team: null,
401	                comment: null,
402	                pub: null,
403	                goalie: null,
404	            }));
405	
406	            return TeamPlayerSchema.parse({
407	                ...playerData,
408	                outcome,
409	                form: [...padding, ...actualForm],
410	            });
411	        });
412	    }
