414	    /**
415	     * Retrieves outcomes by player ID.
416	     * @param playerId - The ID of the player.
417	     * @returns A promise that resolves to an array of outcomes.
418	     * @throws An error if there is a failure.
419	     */
420	    async getByPlayer(playerId: number): Promise<OutcomeType[]> {
