558	    /**
559	     * Calculates a player's recent average for picker logic using the legacy
560	     * PHP behavior:
561	     * - use recent game points before `gameDayId`
562	     * - include at most `history` rows from that list
563	     * - if fewer than `history` games exist, credit 1.45 points per missing game
564	     *
565	     * @param gameDayId - The current game day ID.
566	     * @param playerId - The player ID.
567	     * @param history - Number of recent games to consider.
568	     * @returns A promise resolving to the recent average.
569	     * @throws An error if there is a failure.
570	     */
571	    async getRecentAverage(
572	        gameDayId: number,
573	        playerId: number,
574	        history: number,
575	    ): Promise<number> {
576	        const parsed = z.object({
577	            gameDayId: z.number().int().min(1),
578	            playerId: z.number().int().min(1),
579	            history: z.number().int().min(1),
580	        }).parse({ gameDayId, playerId, history });
581	
582	        const points = await this.getRecentGamePoints(
583	            parsed.gameDayId,
584	            parsed.playerId,
585	        );
586	
587	        let total = 0;
588	        let count = 0;
589	        for (const point of points) {
590	            total += point ?? 0;
591	            count++;
592	            if (count === parsed.history) break;
593	        }
594	
595	        total += 1.45 * (parsed.history - count);
596	        return total / parsed.history;
597	    }
