723	    /**
724	     * Retrieves the win-draw-loss (WDL) statistics for team 'A' based on the bibs each game.
725	     *
726	     * @param {Object} params - The parameters for the query.
727	     * @param {number} [params.year] - The specific year to filter the game days. If not provided, all years are considered.
728	     * @returns {Promise<WDLType>} A promise that resolves to an object containing the counts of games won, drawn, and lost.
729	     * @throws Will throw an error if there is an issue fetching the WDL counts.
730	     */
731	    async getByBibs({ year }: { year?: number }): Promise<WDLType> {
732	        const gameDays = await gameDayService.getAll();
733	        const outcomes = await prisma.outcome.groupBy({
734	            where: {
735	                team: 'A',
736	            },
737	            by: [
738	                'gameDayId',
739	                'team',
740	                'points',
741	            ],
742	        });
743	
744	        return outcomes.reduce((acc, outcome) => {
745	            const gameDay = gameDays.find((gameDay) => gameDay.id === outcome.gameDayId);
746	            if (gameDay &&
747	                gameDay.bibs !== null &&
748	                outcome.points !== null &&
749	                (!year || gameDay.year === year)) {
750	                if (outcome.points === 1) {
751	                    acc.drawn++;
752	                } else {
753	                    if (gameDay.bibs == "A") {
754	                        if (outcome.points === 0) acc.lost++; else acc.won++;
755	                    } else {
756	                        if (outcome.points === 3) acc.lost++; else acc.won++;
757	                    }
758	                }
759	            }
760	            return acc;
761	        }, { won: 0, drawn: 0, lost: 0 });
762	    }
