5	import type { SubmitResponseInput } from '@/types/actions/SubmitResponse';
6	
7	interface SubmitResponseDeps {
8	    gameDayService: Pick<typeof gameDayService, 'get'>;
9	    outcomeService: Pick<typeof outcomeService, 'get' | 'upsert'>;
10	}
11	
12	const defaultDeps: SubmitResponseDeps = {
13	    gameDayService,
14	    outcomeService,
15	};
16	
17	/**
18	 * Submits a response for a player's game day outcome.
19	 *
20	 * Calculates the response interval based on the time elapsed since the game day
21	 * mail was sent, trims and validates the comment, and upserts the outcome
22	 * record with the provided data.
23	 *
24	 * @param data - The response input containing gameDayId, playerId,
25	 * response, goalie, and optional comment
26	 * @param deps - Optional dependency injection object for services
27	 * (gameDayService and outcomeService)
28	 * @returns A promise resolving to the upserted outcome record
29	 * @throws Will throw if gameDay or outcome service operations fail
30	 *
31	 * @example
32	 * const result = await SubmitResponseCore({
33	 *   gameDayId: 1249,
34	 *   playerId: 42,
35	 *   response: 'Yes',
36	 *   goalie: false,
37	 *   comment: 'Player confirmed attendance',
38	 * });
39	 */
40	export async function SubmitResponseCore(
41	    data: SubmitResponseInput,
42	    deps: SubmitResponseDeps = defaultDeps,
43	) {
44	    const gameDay = await deps.gameDayService.get(data.gameDayId);
45	    const existingOutcome = await deps.outcomeService.get(data.gameDayId, data.playerId);
46	
47	    let responseInterval = existingOutcome?.responseInterval ?? null;
48	    if (responseInterval === null && gameDay?.mailSent) {
49	        responseInterval = Math.max(0, Math.floor((Date.now() - gameDay.mailSent.getTime()) / 1000));
50	    }
51	
52	    const comment = data.comment?.trim();
53	
54	    return await deps.outcomeService.upsert({
55	        gameDayId: data.gameDayId,
56	        playerId: data.playerId,
57	        response: data.response,
58	        goalie: data.goalie,
59	        comment: comment && comment.length > 0 ? comment : null,
60	        responseInterval,
61	    });
62	}
