import { PrismaMariaDb } from '@prisma/adapter-mariadb';
import { PrismaClient } from 'prisma/generated/client';

/**
 * A standalone Prisma client for direct test-side database cleanup.
 *
 * This deliberately does not import `@/services/*` or the app's `prisma/prisma`
 * singleton: that singleton is guarded with `import 'server-only'`, which
 * throws when loaded outside Next.js's server bundling. Constructing our own
 * client here (the same pattern `prisma/seed.ci.ts` uses) avoids that guard
 * entirely.
 */
let client: PrismaClient | undefined;

function getClient(): PrismaClient {
    client ??= new PrismaClient({ adapter: new PrismaMariaDb(process.env.DATABASE_URL!) });
    return client;
}

/**
 * Restores a game day's invitation state to how a freshly-seeded database
 * starts: no response recorded for the given player, and no invitation email
 * marked as sent. Tests that drive the real "send invitations, respond"
 * flow should call this once they're done, so the database ends the test
 * exactly as it began regardless of run order or how many times the suite
 * has already exercised this flow.
 */
export async function resetInvitationState(gameDayId: number, playerId: number): Promise<void> {
    const prisma = getClient();
    await prisma.outcome.deleteMany({ where: { gameDayId, playerId } });
    await prisma.gameDay.update({ where: { id: gameDayId }, data: { mailSent: null } });
}

