import 'dotenv/config';

import { PrismaMariaDb } from '@prisma/adapter-mariadb';
import { PrismaClient } from 'prisma/generated/client';

const [, , gameDayIdArg, playerIdArg] = process.argv;
const gameDayId = Number(gameDayIdArg);
const playerId = Number(playerIdArg);

async function main() {
    const adapter = new PrismaMariaDb(process.env.DATABASE_URL!);
    const prisma = new PrismaClient({ adapter });

    await prisma.outcome.deleteMany({ where: { gameDayId, playerId } });
    await prisma.gameDay.update({ where: { id: gameDayId }, data: { mailSent: null } });

    await prisma.$disconnect();
}

main().catch((error) => {
    console.error(error);
    process.exit(1);
});

