import 'dotenv/config';

import { PrismaMariaDb } from '@prisma/adapter-mariadb';
import { PrismaClient } from 'prisma/generated/client';

async function main() {
    const adapter = new PrismaMariaDb(process.env.DATABASE_URL!);
    const prisma = new PrismaClient({ adapter });
    const gd = await prisma.gameDay.findFirst({ orderBy: { date: 'desc' } });
    console.log('sample gameDay:', gd?.id, gd?.date, gd?.mailSent);
    await prisma.$disconnect();
}

main().catch((error) => {
    console.error(error);
    process.exit(1);
});

import { execFileSync } from 'node:child_process';
import path from 'node:path';

const scriptPath = path.join(__dirname, 'resetInvitationState.script.ts');

/**
 * Restores a game day's invitation state to how a freshly-seeded database
 * starts: no response recorded for the given player, and no invitation email
 * marked as sent. Tests that drive the real "send invitations, respond" flow
 * should call this once they're done, so the database ends the test exactly
 * as it began regardless of run order or how many times the suite has
 * already exercised this flow.
 *
 * Runs as a separate `tsx` process (matching `prisma/seed.ci.ts`) rather than
 * importing the generated Prisma client directly into the test file: that
 * client uses `import.meta`, which Playwright's CommonJS test transform
 * can't handle. `execFileSync` inherits `process.env`, which already has
 * `DATABASE_URL` set (by CI directly, or by playwright.config.ts loading
 * `.env.playwright` locally), so no separate env wiring is needed here.
 */
export function resetInvitationState(gameDayId: number, playerId: number): void {
    execFileSync(
        'npx',
        ['tsx', '-r', 'tsconfig-paths/register', scriptPath, String(gameDayId), String(playerId)],
        { stdio: 'inherit' },
    );
}

